using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: Preserve the old discriminator JSON property name ("Discriminator" instead of "$type")
        // so existing documents remain readable and raw SQL filters still work.
        modelBuilder.Entity<Blog>()
            .HasDiscriminator<string>("Discriminator");

        // Fix 2: HasIndex() now throws for Cosmos — removed (it was silently ignored in EF Core 8).
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

